def solve(n,x,d,h):
    min_d=10**9
    for i in range(n):
        if d[i]<min_d:
            min_d=d[i]
    min_h=10**9
    for i in range(n):
        if h[i]<min_h:
            min_h=h[i]
    if min_d>min_h:
        return -1
    else:
        return (x-1)//min_d+1

t=int(input())
for i in range(t):
    n,x=map(int,input().split())
    d=[]
    h=[]
    for i in range(n):
        d1,h1=map(int,input().split())
        d.append(d1)
        h.append(h1)
    print(solve(n,x,d,h))
